cd /tmp/sv-8d6b9b4b72f142c3875c78188afd6c0f/advanced-multi-complexity && dotnet list Enterprise.slnx package --format json | tee /tmp/after-cpm.json | wc -c && cp /tmp/after-cpm.json after-cpm-packages.json && echo "---" && python3 -c "
import json

baseline = json.load(open('/tmp/bp.json'))
after = json.load(open('/tmp/after-cpm.json'))

# Build lookup: project_name -> framework -> package_id -> resolvedVersion
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        lookup[name] = {}
        for fw in proj['frameworks']:
            tfm = fw['framework']
            lookup[name][tfm] = {}
            for pkg in fw.get('topLevelPackages', []):
                lookup[name][tfm][pkg['id']] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

changes = []
unchanged = []

for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for tfm in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        b_pkgs = b.get(proj,{}).get(tfm,{})
        a_pkgs = a.get(proj,{}).get(tfm,{})
        all_ids = sorted(set(list(b_pkgs.keys()) + list(a_pkgs.keys())))
        for pid in all_ids:
            bv = b_pkgs.get(pid, 'N/A')
            av = a_pkgs.get(pid, 'N/A')
            if bv != av:
                changes.append((proj, tfm, pid, bv, av))
            else:
                unchanged.append((proj, tfm, pid, bv))

if changes:
    print('CHANGES:')
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')
else:
    print('NO CHANGES - conversion is version-neutral for all unchanged packages')

print(f'\nTotal unchanged: {len(unchanged)}, Total changed: {len(changes)}')
"

